// // This module implements a 2-to-4 decoder with enable. The decoder has a 2-bit input `in`, an enable input `en`, and a 4-bit output `out`. When `en` is high, the output `out` should be one-hot encoded based on the input `in`. However, when `en` is low, `out` should be set to 1.
module decoder(
	input wire [1:0] in,
	input wire en,
	output reg [3:0] out
);always @(*) begin
		if (en) begin
			case (in)
				2'b00: out = 4'b0001;
				2'b01: out = 4'b0010;
				2'b10: out = 4'b0100;
				2'b11: out = 4'b1000;
				default: out = 4'b0000;
			endcase
		end else
			out = 4'b0000;
	end
endmodule
